import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface RatingDistribution {
  stars: number;
  count: number;
}

interface ProductData {
  product: {
    name: string;
    averageRating: number;
    reviewCount: number;
  };
  ratingDistribution: RatingDistribution[];
}

export default function Widget() {
  const { product, ratingDistribution } = response.data as ProductData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFC107' }}>
              {product.name}
            </Typography>
            <Typography variant="body2" sx={{ color: '#FF5722' }}>
              Average Rating: {product.averageRating} / 5
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              {product.reviewCount} Reviews
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <BarChart
              series={[
                {
                  data: ratingDistribution.map((rating) => rating.count),
                  color: '#FFC107',
                },
              ]}
              xAxis={[
                {
                  data: ratingDistribution.map((rating) => `${rating.stars} Stars`),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#94A3B8',
                  },
                },
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
